83	// RunFunc executes a single agent invocation and returns the Result. Used by
84	// the comparison helpers so the same orchestration logic can be driven by
85	// either the legacy Runner or the agent service.
86	type RunFunc func(opts RunOptions) (*Result, error)
87	
88	// RunCompareWith dispatches the same prompt to multiple harnesses, executing
89	// each arm via run, and returns a ComparisonRecord. Production callers should
90	// use RunCompareViaService; tests may pass Runner.Run as the closure.
91	func RunCompareWith(run RunFunc, opts CompareOptions, resolvePrompt func(RunOptions) (string, error), cleanupSandbox func(repoDir, compareID string)) (*ComparisonRecord, error) {
92		if len(opts.Harnesses) == 0 {
93			return nil, fmt.Errorf("agent: compare requires at least one harness")
94		}
95		if resolvePrompt == nil {
96			resolvePrompt = defaultResolvePromptForCompare
97		}
98	
99		prompt, err := resolvePrompt(opts.RunOptions)
100		if err != nil {
101			return nil, err
102		}
103	
104		id := genCompareID()
105		record := &ComparisonRecord{
106			ID:        id,
107			Timestamp: time.Now().UTC(),
108			Prompt:    prompt,
109			Arms:      make([]ComparisonArm, len(opts.Harnesses)),
110		}
111	
112		baseDir := opts.WorkDir
113		if baseDir == "" {
114			baseDir, _ = os.Getwd()
115		}
116	
117		worktrees := make([]string, len(opts.Harnesses))
118		if opts.Sandbox {
119			for i, harness := range opts.Harnesses {
120				label := harness
121				if l, ok := opts.ArmLabels[i]; ok {
122					label = l
123				}
124				wt, err := createCompareWorktree(baseDir, id, label)
125				if err != nil {
126					record.Arms[i] = ComparisonArm{
127						Harness:  label,
128						ExitCode: 1,
129						Error:    fmt.Sprintf("worktree: %s", err),
130					}
131					continue
132				}
133				worktrees[i] = wt
134			}
135		}
136	
137		var wg sync.WaitGroup
138		for i, harness := range opts.Harnesses {
139			if opts.Sandbox && worktrees[i] == "" && record.Arms[i].Error != "" {
140				continue
141			}
142			wg.Add(1)
143			go func(idx int, harnessName string) {
144				defer wg.Done()
145				record.Arms[idx] = runCompareArmWith(run, opts, idx, harnessName, baseDir, prompt, worktrees[idx])
146			}(i, harness)
147		}
148		wg.Wait()
149	
150		if opts.Sandbox && !opts.KeepSandbox {
151			if cleanupSandbox != nil {
152				cleanupSandbox(baseDir, id)
153			} else {
154				cleanupCompareWorktrees(baseDir, id)
155			}
156		}
157	
158		return record, nil
159	}
