161	// RunCompareViaService is the production replacement for Runner.RunCompare.
162	// It resolves prompts from inline text or PromptFile and drives each arm
163	// through the agent service (RunViaService).
164	func RunCompareViaService(ctx context.Context, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
165		run := func(runOpts RunOptions) (*Result, error) {
166			return RunViaService(ctx, workDir, runOpts)
167		}
168		return RunCompareWith(run, opts, defaultResolvePromptForCompare, cleanupCompareWorktrees)
169	}
