171	// RunCompareWithAgent calls RunCompareViaService using a pre-built DdxAgent.
172	// Suitable for callers that want to reuse a service instance.
173	func RunCompareWithAgent(ctx context.Context, agent agentlib.DdxAgent, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
174		run := func(runOpts RunOptions) (*Result, error) {
175			return RunViaServiceWith(ctx, agent, workDir, runOpts)
176		}
177		return RunCompareWith(run, opts, defaultResolvePromptForCompare, cleanupCompareWorktrees)
178	}
