180	// defaultResolvePromptForCompare reads inline Prompt or PromptFile.
181	func defaultResolvePromptForCompare(opts RunOptions) (string, error) {
182		prompt := opts.Prompt
183		if opts.PromptFile != "" {
184			data, err := os.ReadFile(opts.PromptFile)
185			if err != nil {
186				return "", fmt.Errorf("agent: read prompt file: %w", err)
187			}
188			prompt = string(data)
189		}
190		if prompt == "" {
191			return "", fmt.Errorf("agent: prompt is required")
192		}
193		return prompt, nil
194	}
