196	func runCompareArmWith(run RunFunc, opts CompareOptions, armIdx int, harnessName, baseDir, prompt, worktreePath string) ComparisonArm {
197		label := harnessName
198		if l, ok := opts.ArmLabels[armIdx]; ok {
199			label = l
200		}
201		arm := ComparisonArm{Harness: label}
202	
203		workDir := baseDir
204		if worktreePath != "" {
205			workDir = worktreePath
206		}
207	
208		model := opts.Model
209		if m, ok := opts.ArmModels[armIdx]; ok {
210			model = m
211		}
212	
213		runOpts := RunOptions{
214			Harness:     harnessName,
215			Prompt:      prompt,
216			Model:       model,
217			Effort:      opts.Effort,
218			Timeout:     opts.Timeout,
219			WorkDir:     workDir,
220			Permissions: opts.Permissions,
221			Correlation: opts.Correlation,
222		}
223	
224		result, err := run(runOpts)
225		if err != nil {
226			arm.ExitCode = 1
227			arm.Error = err.Error()
228		} else {
229			arm.Model = result.Model
230			arm.Output = result.Output
231			arm.ToolCalls = result.ToolCalls
232			arm.Tokens = result.Tokens
233			arm.InputTokens = result.InputTokens
234			arm.OutputTokens = result.OutputTokens
235			arm.CostUSD = result.CostUSD
236			arm.DurationMS = result.DurationMS
237			arm.ExitCode = result.ExitCode
238			arm.Error = result.Error
239		}
240	
241		if worktreePath != "" {
242			arm.Diff = captureGitDiff(worktreePath)
243		}
244	
245		if opts.PostRun != "" && workDir != "" {
246			out, ok := runPostCommand(workDir, opts.PostRun)
247			arm.PostRunOut = out
248			arm.PostRunOK = &ok
249		}
250	
251		return arm
252	}
