433	// QuorumMet returns true if enough results succeeded.
434	func QuorumMet(strategy string, threshold int, results []*Result) bool {
435		total := len(results)
436		eff := effectiveThreshold(strategy, threshold, total)
437		successes := 0
438		for _, r := range results {
439			if r != nil && r.ExitCode == 0 {
440				successes++
441			}
442		}
443		return successes >= eff
444	}
445	
446	func effectiveThreshold(strategy string, threshold, total int) int {
447		switch strategy {
448		case "any":
449			return 1
450		case "majority":
451			return (total / 2) + 1
452		case "unanimous":
453			return total
454		default:
455			if threshold > 0 {
456				return threshold
457			}
458			return 1
459		}
460	}
