462	// CondenseOutput filters raw agent output to keep only progress-relevant lines.
463	// The canonical implementation lives in agent/internal/comparison.CondenseOutput.
464	func CondenseOutput(input, namespacePrefix string) string {
465		var kept []string
466		skippingTokens := false
467		skippingDiff := false
468		blankRun := 0
469		lastWasKept := false
470		keepNextResult := false
471	
472		lines := strings.Split(input, "\n")
473		if len(lines) > 0 && lines[len(lines)-1] == "" {
474			lines = lines[:len(lines)-1]
475		}
476	
477		for _, line := range lines {
478			if strings.HasPrefix(line, "Commands run:") {
479				continue
480			}
481			if line == "tokens used" {
482				skippingTokens = true
483				continue
484			}
485			if skippingTokens {
486				skippingTokens = false
487				continue
488			}
489			if condenseIsDiffHeader(line) {
490				skippingDiff = true
491				continue
492			}
493			if skippingDiff {
494				if condenseIsDiffHeader(line) {
495					continue
496				}
497				if len(line) > 0 && (line[0] == '+' || line[0] == '-' || line[0] == ' ') {
498					continue
499				}
500				skippingDiff = false
501			}
502			if line == "" {
503				blankRun++
504				continue
505			}
506			keep := false
507			if keepNextResult {
508				keep = true
509				keepNextResult = false
510			}
511			if namespacePrefix != "" && strings.HasPrefix(line, namespacePrefix) {
512				keep = true
513			}
514			if strings.HasPrefix(line, "$ ") {
515				keep = true
516				keepNextResult = true
517			}
518			for _, kw := range []string{"error", "Error", "ERROR", "warning", "Warning", "WARN", "FAIL", "fail", "panic"} {
519				if strings.Contains(line, kw) {
520					keep = true
521					break
522				}
523			}
524			for _, kw := range []string{"hx-", "helix-", "FEAT-", "US-", "COMPLETE", "BLOCKED", "CLOSED", "closed", "commit "} {
525				if strings.Contains(line, kw) {
526					keep = true
527					break
528				}
529			}
530			if len(line) > 0 && condenseIsAlphaNumUnderscore(rune(line[0])) && strings.Contains(line, ":") {
531				keep = true
532			}
533			if strings.HasPrefix(line, "#") || strings.HasPrefix(line, "|") || strings.HasPrefix(line, " |") || strings.HasPrefix(line, "**") {
534				keep = true
535			}
536			if strings.HasPrefix(line, "Phase") || strings.HasPrefix(line, "Step") || strings.HasPrefix(line, "---") {
537				keep = true
538			}
539			if keep {
540				if lastWasKept && blankRun > 0 {
541					kept = append(kept, "")
542				}
543				blankRun = 0
544				lastWasKept = true
545				kept = append(kept, line)
546			}
547		}
548	
549		if len(kept) == 0 {
550			return ""
551		}
552		result := strings.Join(kept, "\n")
553		return condenseTrimBlankLines(result)
554	}
555	
556	func condenseIsDiffHeader(line string) bool {
557		return strings.HasPrefix(line, "diff --git ") ||
558			strings.HasPrefix(line, "index ") ||
559			strings.HasPrefix(line, "--- a/") ||
560			strings.HasPrefix(line, "+++ b/") ||
561			strings.HasPrefix(line, "@@ ")
562	}
563	
564	func condenseIsAlphaNumUnderscore(r rune) bool {
565		return (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_'
566	}
567	
568	func condenseTrimBlankLines(s string) string {
569		lines := strings.Split(s, "\n")
570		start := 0
571		for start < len(lines) && strings.TrimSpace(lines[start]) == "" {
572			start++
573		}
574		end := len(lines)
575		for end > start && strings.TrimSpace(lines[end-1]) == "" {
576			end--
577		}
578		return strings.Join(lines[start:end], "\n")
579	}
