581	// LoadBenchmarkSuite reads a benchmark suite from a JSON file.
582	// The canonical implementation lives in agent/internal/comparison.
583	func LoadBenchmarkSuite(path string) (*BenchmarkSuite, error) {
584		data, err := os.ReadFile(path)
585		if err != nil {
586			return nil, fmt.Errorf("reading benchmark suite: %w", err)
587		}
588		var suite BenchmarkSuite
589		if err := json.Unmarshal(data, &suite); err != nil {
590			return nil, fmt.Errorf("parsing benchmark suite: %w", err)
591		}
592		return &suite, nil
593	}
