659	func benchSummarize(result *BenchmarkResult) BenchmarkSummary {
660		summary := BenchmarkSummary{
661			TotalPrompts: len(result.Comparisons),
662		}
663		armStats := make(map[string]*BenchmarkArmSummary)
664		armOrder := make([]string, len(result.Arms))
665		for i, arm := range result.Arms {
666			label := arm.Label
667			armOrder[i] = label
668			armStats[label] = &BenchmarkArmSummary{Label: label}
669		}
670		for _, cmp := range result.Comparisons {
671			for _, arm := range cmp.Arms {
672				stats, ok := armStats[arm.Harness]
673				if !ok {
674					continue
675				}
676				if arm.ExitCode == 0 {
677					stats.Completed++
678				} else {
679					stats.Failed++
680				}
681				stats.TotalTokens += arm.Tokens
682				stats.TotalCostUSD += arm.CostUSD
683				stats.AvgDurationMS += arm.DurationMS
684			}
685		}
686		for _, label := range armOrder {
687			stats := armStats[label]
688			total := stats.Completed + stats.Failed
689			if total > 0 {
690				stats.AvgDurationMS = stats.AvgDurationMS / total
691			}
692			summary.Arms = append(summary.Arms, *stats)
693		}
694		return summary
695	}
