393	func synthesizeCommitExcludePathspecs(dir string) []string {
394		candidates := []struct {
395			pathspec    string
396			ignoreProbe string
397		}{
398			{
399				pathspec:    ":(exclude).ddx/executions/*/embedded",
400				ignoreProbe: ".ddx/executions/.ddx-check-ignore/embedded",
401			},
402			{
403				pathspec:    ":(exclude).ddx/executions/*/no_changes_rationale.txt",
404				ignoreProbe: ".ddx/executions/.ddx-check-ignore/no_changes_rationale.txt",
405			},
406			{
407				pathspec:    ":(exclude).claude/skills",
408				ignoreProbe: ".claude/skills",
409			},
410			{
411				pathspec:    ":(exclude).agents/skills",
412				ignoreProbe: ".agents/skills",
413			},
414		}
415	
416		pathspecs := make([]string, 0, len(candidates))
417		for _, c := range candidates {
418			if isGitIgnored(dir, c.ignoreProbe) {
419				continue
420			}
421			pathspecs = append(pathspecs, c.pathspec)
422		}
423		return pathspecs
424	}
