364		out, err := osexec.Command("git", "-C", dir, "worktree", "add", "--force", "--detach", path, rev).CombinedOutput()
365		if err != nil {
366			return fmt.Errorf("git worktree add %s %s: %s: %w", path, rev, strings.TrimSpace(string(out)), err)
367		}
