405	func (RealLandingGitOps) PushFFOnly(dir, remote, localRef, targetBranch string) error {
406		// Refspec "<local>:<remote>" with no '+' prefix → fast-forward only.
407		refspec := fmt.Sprintf("%s:refs/heads/%s", localRef, targetBranch)
408		out, err := osexec.Command("git", "-C", dir, "push", remote, refspec).CombinedOutput()
409		if err != nil {
410			return fmt.Errorf("git push %s %s: %s: %w", remote, refspec, strings.TrimSpace(string(out)), err)
411		}
412		return nil
413	}
