415	func (RealLandingGitOps) CountCommits(dir, base, tip string) int {
416		out, err := osexec.Command("git", "-C", dir, "rev-list", "--count", base+".."+tip).CombinedOutput()
417		if err != nil {
418			return 0
419		}
420		s := strings.TrimSpace(string(out))
421		n := 0
422		for _, c := range s {
423			if c >= '0' && c <= '9' {
424				n = n*10 + int(c-'0')
425			}
426		}
427		return n
428	}
