430	func (RealLandingGitOps) StageDir(dir, relPath string) error {
431		// Exclude embedded session logs from the evidence commit — tracking
432		// multi-thousand-line .jsonl files caused retry review prompts to
433		// balloon past 2M tokens and crash every provider with n_keep > n_ctx
434		// (ddx-39e27896). manifest.json, result.json, prompt.md, and
435		// usage.json remain tracked for audit; the raw session log lives on
436		// disk, not in git history.
437		args := append([]string{"-C", dir, "add", "--", relPath}, EvidenceLandExcludePathspecs()...)
438		out, err := osexec.Command("git", args...).CombinedOutput()
439		if err != nil {
440			return fmt.Errorf("git add %s: %s: %w", relPath, strings.TrimSpace(string(out)), err)
441		}
442		return nil
443	}
