445	func (RealLandingGitOps) CommitStaged(dir, msg string) (string, error) {
446		out, _ := osexec.Command("git", "-C", dir, "diff", "--cached", "--name-only").Output()
447		if len(strings.TrimSpace(string(out))) == 0 {
448			return "", nil
449		}
450		commitOut, err := osexec.Command("git", "-C", dir,
451			"-c", "user.name=ddx-land-coordinator",
452			"-c", "user.email=coordinator@ddx.local",
