457		}
458		shaOut, err := osexec.Command("git", "-C", dir, "rev-parse", "HEAD").Output()
459		if err != nil {
460			return "", fmt.Errorf("rev-parse HEAD after evidence commit: %w", err)
461		}
462		return strings.TrimSpace(string(shaOut)), nil
463	}
