package agent

// execute_bead_hook_env_test.go — regression test for ddx-aa8a5fb3 (hook
// env contamination) as migrated in Phase 2a (ddx-65b88ae1).
//
// Simulates a git-hook caller environment: GIT_DIR + GIT_WORK_TREE point at
// a throwaway bare repo. We then drive the high-blast-radius execute-bead
// git paths (WorktreeAdd, SynthesizeCommit, UpdateRef, landing refs,
// CommitTracker) against a SEPARATE project repo and assert that the fake
// bare repo's config file is never mutated. Before the git.Command wrapper
// scrubbed inherited GIT_* env, those operations would flip the bare repo's
// core.bare / core.worktree entries.

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// setupFakeHookBareRepo initializes a bare repo at a temp path and returns
// (barePath, cleanupEnv) where cleanupEnv restores any GIT_* vars the test
// replaces.
func setupFakeHookBareRepo(t *testing.T) string {
	t.Helper()
	bare := filepath.Join(t.TempDir(), "outer.git")
	cmd := exec.Command("git", "init", "--bare", "-b", "main", bare)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("git init --bare: %s: %v", string(out), err)
	}
	return bare
}

// setHookEnv sets GIT_DIR and GIT_WORK_TREE via t.Setenv so each test restores
// the previous values on teardown.
func setHookEnv(t *testing.T, gitDir, workTree string) {
	t.Helper()
	t.Setenv("GIT_DIR", gitDir)
	t.Setenv("GIT_WORK_TREE", workTree)
}

// readConfig reads the raw bytes of the bare repo's config file. The
// regression anchor is byte-for-byte equality: any inherited GIT_* leak would
// cause git to rewrite core.bare / add core.worktree lines.
func readConfig(t *testing.T, bare string) []byte {
	t.Helper()
	data, err := os.ReadFile(filepath.Join(bare, "config"))
	if err != nil {
		t.Fatalf("read bare config: %v", err)
	}
	return data
}

// initProjectRepo creates a fresh non-bare repo with one commit, used as the
// target of execute-bead operations.
func initProjectRepo(t *testing.T) (dir, headSHA string) {
	t.Helper()
	dir = t.TempDir()
	runPlain := func(args ...string) string {
		c := exec.Command("git", append([]string{"-C", dir}, args...)...)
		out, err := c.CombinedOutput()
		if err != nil {
			t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), err)
		}
		return strings.TrimSpace(string(out))
	}
	runPlain("init", "-b", "main")
	runPlain("config", "user.name", "Test")
	runPlain("config", "user.email", "test@example.com")
	if err := os.WriteFile(filepath.Join(dir, "README.md"), []byte("# x\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	runPlain("add", "-A")
	runPlain("commit", "-m", "init")
	headSHA = runPlain("rev-parse", "HEAD")
	return dir, headSHA
}

func TestExecuteBead_HookEnvContamination_NoLeakToBareConfig(t *testing.T) {
	bare := setupFakeHookBareRepo(t)
	configBefore := readConfig(t, bare)

	projectDir, baseSHA := initProjectRepo(t)

	// Contaminate the process env the way a git hook would.
	setHookEnv(t, filepath.Join(bare), projectDir)

	git := &RealGitOps{}

	// --- WorktreeAdd / WorktreeList / WorktreeRemove / WorktreePrune ---
	wtPath := filepath.Join(t.TempDir(), "wt")
	if err := git.WorktreeAdd(projectDir, wtPath, baseSHA); err != nil {
		t.Fatalf("WorktreeAdd: %v", err)
	}
	if _, err := git.WorktreeList(projectDir); err != nil {
		t.Fatalf("WorktreeList: %v", err)
	}

	// Write a real change inside the worktree so SynthesizeCommit actually
	// stages and commits something, exercising the add/commit path that
	// previously committed Bug B's bad symlinks.
	if err := os.WriteFile(filepath.Join(wtPath, "hello.txt"), []byte("hi\n"), 0o644); err != nil {
		t.Fatal(err)
	}

	// RealGitOps.SynthesizeCommit requires a git user identity; inject one
	// via config on the worktree's main repo so the commit step succeeds.
	setIdentity := func(dir string) {
		c := exec.Command("git", "-C", dir, "config", "user.name", "Synth")
		if out, err := c.CombinedOutput(); err != nil {
			t.Fatalf("config user.name: %s: %v", string(out), err)
		}
		c = exec.Command("git", "-C", dir, "config", "user.email", "synth@example.com")
		if out, err := c.CombinedOutput(); err != nil {
			t.Fatalf("config user.email: %s: %v", string(out), err)
		}
	}
	setIdentity(projectDir)

	committed, err := git.SynthesizeCommit(wtPath, "test: synth")
	if err != nil {
		t.Fatalf("SynthesizeCommit: %v", err)
	}
	if !committed {
		t.Fatalf("SynthesizeCommit: expected a commit to be made")
	}
	resultSHA, err := git.HeadRev(wtPath)
	if err != nil {
		t.Fatalf("HeadRev: %v", err)
	}

	// --- UpdateRef / DeleteRef (landing/preserve refs) ---
	preserveRef := fmt.Sprintf("refs/ddx/iterations/test-bead/%s", resultSHA[:8])
	if err := git.UpdateRef(projectDir, preserveRef, resultSHA); err != nil {
		t.Fatalf("UpdateRef: %v", err)
	}
	if err := git.DeleteRef(projectDir, preserveRef); err != nil {
		t.Fatalf("DeleteRef: %v", err)
	}

	// --- WorktreeRemove / WorktreePrune ---
	if err := git.WorktreeRemove(projectDir, wtPath); err != nil {
		t.Fatalf("WorktreeRemove: %v", err)
	}
	if err := git.WorktreePrune(projectDir); err != nil {
		t.Fatalf("WorktreePrune: %v", err)
	}

	// --- CommitTracker (writes .ddx/beads.jsonl in project) ---
	trackerDir := filepath.Join(projectDir, ".ddx")
	if err := os.MkdirAll(trackerDir, 0o755); err != nil {
		t.Fatal(err)
	}
	trackerPath := filepath.Join(trackerDir, "beads.jsonl")
	// Write one bead event so there is real content to commit. Use the bead
	// package's JSON to keep the file schema valid.
	b := bead.Bead{ID: "test-bead", Title: "hook-env regression"}
	data, err := bead.MarshalBead(b)
	if err != nil {
		t.Fatalf("marshal bead: %v", err)
	}
	if err := os.WriteFile(trackerPath, append(data, '\n'), 0o644); err != nil {
		t.Fatal(err)
	}
	if err := CommitTracker(context.Background(), projectDir); err != nil {
		// CommitTracker is best-effort for missing config in some paths; the
		// important assertion is still that the bare repo config is untouched.
		t.Logf("CommitTracker: %v", err)
	}

	// --- Assertion: bare repo config is byte-identical ---
	configAfter := readConfig(t, bare)
	if string(configBefore) != string(configAfter) {
		t.Fatalf("bare repo config was mutated by hook-env leak\nBEFORE:\n%s\nAFTER:\n%s",
			string(configBefore), string(configAfter))
	}
}

